// multi-tile driver.

const GRAY_TILED_PGM: &[u8] = include_bytes!("fixtures/opj128_gray_tiled_prec.pgm");
const GRAY_TILED_LRCP_J2K: &[u8] = include_bytes!("fixtures/opj128_gray_tiled_prec_lrcp.j2k");
